// AppLogger.kt
import timber.log.Timber

object AppLogger {

    private const val TAG_AUTH = "Authentication"
    private const val TAG_DB = "Database"
    private const val TAG_API = "API"
    private const val TAG_EXCEPTION = "Exception"

    /**
     * Logs a user authentication attempt.
     * @param username The username attempting to authenticate.
     */
    fun logAuthAttempt(username: String) {
        Timber.i("$TAG_AUTH: User '$username' is attempting to authenticate.")
    }

    /**
     * Logs a successful user authentication.
     * @param username The username that successfully authenticated.
     */
    fun logAuthSuccess(username: String) {
        Timber.v("$TAG_AUTH: SUCCESS: User '$username' authenticated successfully.")
    }

    /**
     * Logs a failed user authentication attempt.
     * @param username The username that failed to authenticate.
     * @param reason A brief description of why the authentication failed (e.g., "invalid credentials").
     */
    fun logAuthFailure(username: String, reason: String) {
        Timber.w("$TAG_AUTH: FAILED: User '$username' failed authentication. Reason: '$reason'.")
    }

    /**
     * Logs a database query with its parameters.
     *
     * @param query The SQL query string.
     * @param params A map of parameters used in the query (e.g., for prepared statements). Can be null if no params.
     */
    fun logDbQuery(query: String, params: Map<String, Any?>?) {
        val paramsString = params?.entries?.joinToString(", ") { "${it.key}='${it.value}'" } ?: "No parameters"
        Timber.d("$TAG_DB: Executing query: '$query'. Parameters: {$paramsString}")
    }

    /**
     * Logs details of an outgoing API request.
     *
     * This function should ideally be called from an OkHttp Interceptor or similar network layer.
     *
     * @param method The HTTP method (e.g., "GET", "POST").
     * @param url The full URL of the request.
     * @param headers A map of request headers. Can be null.
     * @param body The request body as a string. Can be null if no body.
     */
    fun logApiRequest(method: String, url: String, headers: Map<String, String>?, body: String?) {
        val headersString = headers?.entries?.joinToString("\n    ") { "${it.key}: ${it.value}" } ?: "No headers"
        val bodyString = body?.takeIf { it.isNotBlank() } ?: "No body"

        Timber.v("""
            $TAG_API REQUEST:
            Method: $method
            URL: $url
            Headers:
                $headersString
            Body:
                $bodyString
        """.trimIndent())
    }

    /**
     * Logs details of an incoming API response.
     *
     * This function should ideally be called from an OkHttp Interceptor or similar network layer.
     *
     * @param method The HTTP method of the original request.
     * @param url The full URL of the original request.
     * @param statusCode The HTTP status code of the response (e.g., 200, 404).
     * @param headers A map of response headers. Can be null.
     * @param body The response body as a string. Can be null if no body.
     * @param durationMillis The time taken for the request-response cycle in milliseconds.
     */
    fun logApiResponse(method: String, url: String, statusCode: Int, headers: Map<String, String>?, body: String?, durationMillis: Long? = null) {
        val headersString = headers?.entries?.joinToString("\n    ") { "${it.key}: ${it.value}" } ?: "No headers"
        val bodyString = body?.takeIf { it.isNotBlank() } ?: "No body"
        val duration = durationMillis?.let { " (${it}ms)" } ?: ""

        // Use 'e' for client/server errors (>= 400), 'w' for redirects (3xx), 'i' for success (2xx), 'v' for others
        val priority = when {
            statusCode >= 400 -> Timber::e
            statusCode >= 300 -> Timber::w
            statusCode >= 200 -> Timber::i
            else -> Timber::v
        }

        priority.invoke("""
            $TAG_API RESPONSE$duration:
            Method: $method
            URL: $url
            Status: $statusCode
            Headers:
                $headersString
            Body:
                $bodyString
        """.trimIndent())
    }

    /**
     * Logs an exception with its stack trace.
     * This is a general-purpose exception logger.
     *
     * @param throwable The Throwable object (exception or error).
     * @param message An optional context message for the exception.
     */
    fun logException(throwable: Throwable, message: String? = null) {
        val msg = message?.let { "$TAG_EXCEPTION: $it" } ?: TAG_EXCEPTION
        Timber.e(throwable, msg)
    }

    /**
     * Logs a generic verbose message with a custom tag.
     */
    fun logVerbose(tag: String, message: String) {
        Timber.v("$tag: $message")
    }

    /**
     * Logs a generic debug message with a custom tag.
     */
    fun logDebug(tag: String, message: String) {
        Timber.d("$tag: $message")
    }

    /**
     * Logs a generic info message with a custom tag.
     */
    fun logInfo(tag: String, message: String) {
        Timber.i("$tag: $message")
    }

    /**
     * Logs a generic warning message with a custom tag.
     */
    fun logWarning(tag: String, message: String) {
        Timber.w("$tag: $message")
    }

    /**
     * Logs a generic error message with a custom tag.
     */
    fun logError(tag: String, message: String, throwable: Throwable? = null) {
        if (throwable != null) {
            Timber.e(throwable, "$tag: $message")
        } else {
            Timber.e("$tag: $message")
        }
    }
}

